268	    /*
269	     * Direct convolution with fused bias + requantize.
270	     * Vectorizes across out_tensor_ch: vqmacc.vx accumulates one input scalar
271	     * against the full transposed weight row (all output channels).
272	     * Processes 4 output pixels at a time, sharing weight loads.
273	     * Eliminates im2col buffer and q32 intermediate buffer.
274	     *
275	     * Register plan:
276	     *   v0-v3   (M4 e32): Accumulator pixel 1
277	     *   v4-v7   (M4 e32): Accumulator pixel 2
278	     *   v8-v11  (M4 e32): Accumulator pixel 3
279	     *   v12-v15 (M4 e32): Accumulator pixel 4
280	     *   v16     (M1 e8):  Weight vector load
281	     */
282	    const int in_tensor_ch = 3;
283	    long i_ker_y, i_ker_x, ch;
284	
285	    const long align_byte = 64;
286	    q7_t *pOut = out_tensor;
287	    long vl;
288	
289	    /* Allocate transposed weight buffer from in_tmp_buf */
290	    q7_t *src2 = (q7_t *)in_tmp_buf;
291	    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);
292	
293	    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
294	    const long row = out_tensor_ch;
295	    const long col = ker_dim * ker_dim * in_tensor_ch;
296	    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
297	
298	    /* Total output pixels */
299	    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
300	    long pixel_idx = 0;
301	
302	    /* Process 4 output pixels at a time */
303	    for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
304	    {
305	        long out_y1 = pixel_idx / out_tensor_dim;
306	        long out_x1 = pixel_idx % out_tensor_dim;
307	        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
308	        long out_x2 = (pixel_idx + 1) % out_tensor_dim;
309	        long out_y3 = (pixel_idx + 2) / out_tensor_dim;
310	        long out_x3 = (pixel_idx + 2) % out_tensor_dim;
311	        long out_y4 = (pixel_idx + 3) / out_tensor_dim;
312	        long out_x4 = (pixel_idx + 3) % out_tensor_dim;
313	
314	        /* Channel-striping loop: process out_tensor_ch in VLMAX-sized chunks */
315	        long ch_off = 0;
316	        while (ch_off < out_tensor_ch)
317	        {
318	            long ch_remain = out_tensor_ch - ch_off;
319	
320	            /* Load bias into 4 M4 accumulators at e32/M4 */
321	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
322	            NDS_VEC_VLE32_V(NDS_VEC_V0, bias + ch_off);
323	            NDS_VEC_VLE32_V(NDS_VEC_V4, bias + ch_off);
324	            NDS_VEC_VLE32_V(NDS_VEC_V8, bias + ch_off);
325	            NDS_VEC_VLE32_V(NDS_VEC_V12, bias + ch_off);
326	
327	            /* Set e8/M1 once for all vqmacc accumulation (e8*e8->e32, M1 input, M4 acc) */
328	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
329	
330	            /* Accumulate over all K positions */
331	            if (pad == 0)
332	            {
333	                /* Fast path: no padding means all pixels are interior — skip boundary checks */
334	                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
335	                {
336	                    long in_row1 = out_y1 * stride + i_ker_y;
337	                    long in_row2 = out_y2 * stride + i_ker_y;
338	                    long in_row3 = out_y3 * stride + i_ker_y;
339	                    long in_row4 = out_y4 * stride + i_ker_y;
340	
341	                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
342	                    {
343	                        long in_col1 = out_x1 * stride + i_ker_x;
344	                        long in_col2 = out_x2 * stride + i_ker_x;
345	                        long in_col3 = out_x3 * stride + i_ker_x;
346	                        long in_col4 = out_x4 * stride + i_ker_x;
347	                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
348	
349	                        for (ch = 0; ch < in_tensor_ch; ch++)
350	                        {
351	                            long k_pos = k_base + ch;
352	
353	                            /* Load transposed weight row into v16 at e8/M1 */
354	                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
355	
356	                            /* Get input scalars — no boundary checks needed */
357	                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
358	                            q7_t a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
359	                            q7_t a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
360	                            q7_t a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
361	
362	                            /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
363	                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
364	                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
365	                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
366	                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
367	                        }
368	                    }
369	                }
370	            }
371	            else
372	            {
373	                /* General path: check boundaries for padding */
374	                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
375	                {
376	                    long in_row1 = out_y1 * stride - pad + i_ker_y;
377	                    long in_row2 = out_y2 * stride - pad + i_ker_y;
378	                    long in_row3 = out_y3 * stride - pad + i_ker_y;
379	                    long in_row4 = out_y4 * stride - pad + i_ker_y;
380	
381	                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
382	                    {
383	                        long in_col1 = out_x1 * stride - pad + i_ker_x;
384	                        long in_col2 = out_x2 * stride - pad + i_ker_x;
385	                        long in_col3 = out_x3 * stride - pad + i_ker_x;
386	                        long in_col4 = out_x4 * stride - pad + i_ker_x;
387	                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
388	
389	                        for (ch = 0; ch < in_tensor_ch; ch++)
390	                        {
391	                            long k_pos = k_base + ch;
392	
393	                            /* Load transposed weight row into v16 at e8/M1 */
394	                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
395	
396	                            /* Get input scalars with boundary checks */
397	                            q7_t a1 = 0, a2 = 0, a3 = 0, a4 = 0;
398	                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
399	                                in_col1 >= 0 && in_col1 < in_tensor_dim)
400	                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
401	                            if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
402	                                in_col2 >= 0 && in_col2 < in_tensor_dim)
403	                                a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
404	                            if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
405	                                in_col3 >= 0 && in_col3 < in_tensor_dim)
406	                                a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
407	                            if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
408	                                in_col4 >= 0 && in_col4 < in_tensor_dim)
409	                                a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
410	
411	                            /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
412	                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
413	                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
414	                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
415	                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
416	                        }
417	                    }
418	                }
419	            }
420	
421	            /* Requantize pixel 1: shift, scale, narrow, clip, store */
422	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
423	            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
424	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
425	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
426	            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
427	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
428	            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
429	            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);
430	
431	            /* Requantize pixel 2 */
432	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
433	            NDS_VEC_VSRA_VX(NDS_VEC_V4, NDS_VEC_V4, pre_rshift);
434	            NDS_VEC_VMUL_VX(NDS_VEC_V4, NDS_VEC_V4, out_scale);
435	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
436	            NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, post_rshift);
437	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
438	            NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, 0);
439	            NDS_VEC_VSB_V(NDS_VEC_V4, pOut + out_tensor_ch + ch_off);
440	
441	            /* Requantize pixel 3 */
442	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
443	            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
444	            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
445	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
446	            NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
447	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
448	            NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, 0);
449	            NDS_VEC_VSB_V(NDS_VEC_V8, pOut + 2 * out_tensor_ch + ch_off);
450	
451	            /* Requantize pixel 4 */
452	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
453	            NDS_VEC_VSRA_VX(NDS_VEC_V12, NDS_VEC_V12, pre_rshift);
454	            NDS_VEC_VMUL_VX(NDS_VEC_V12, NDS_VEC_V12, out_scale);
455	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
456	            NDS_VEC_VNCLIP_WX(NDS_VEC_V12, NDS_VEC_V12, post_rshift);
457	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
458	            NDS_VEC_VNCLIP_WX(NDS_VEC_V12, NDS_VEC_V12, 0);
459	            NDS_VEC_VSB_V(NDS_VEC_V12, pOut + 3 * out_tensor_ch + ch_off);
460	
461	            ch_off += vl;
462	        }
463	        pOut += 4 * out_tensor_ch;
464	    }
465	
466	    /* Handle remaining 0-3 pixels one at a time */
467	    for (; pixel_idx < total_pixels; pixel_idx++)
468	    {
469	        long out_y1 = pixel_idx / out_tensor_dim;
470	        long out_x1 = pixel_idx % out_tensor_dim;
471	
472	        /* Channel-striping loop */
473	        long ch_off = 0;
474	        while (ch_off < out_tensor_ch)
475	        {
476	            long ch_remain = out_tensor_ch - ch_off;
477	
478	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
479	            NDS_VEC_VLE32_V(NDS_VEC_V0, bias + ch_off);
480	
481	            /* Set e8/M1 once for all vqmacc accumulation */
482	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
483	
484	            if (pad == 0)
485	            {
486	                /* Fast path: no padding — skip boundary checks */
487	                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
488	                {
489	                    long in_row1 = out_y1 * stride + i_ker_y;
490	                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
491	                    {
492	                        long in_col1 = out_x1 * stride + i_ker_x;
493	                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
494	                        for (ch = 0; ch < in_tensor_ch; ch++)
495	                        {
496	                            long k_pos = k_base + ch;
497	                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
498	                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
499	                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
500	                        }
501	                    }
502	                }
503	            }
504	            else
505	            {
506	                /* General path: check boundaries for padding */
507	                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
508	                {
509	                    long in_row1 = out_y1 * stride - pad + i_ker_y;
510	                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
511	                    {
512	                        long in_col1 = out_x1 * stride - pad + i_ker_x;
513	                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
514	                        for (ch = 0; ch < in_tensor_ch; ch++)
515	                        {
516	                            long k_pos = k_base + ch;
517	                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
518	                            q7_t a1 = 0;
519	                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
520	                                in_col1 >= 0 && in_col1 < in_tensor_dim)
521	                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
522	                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
523	                        }
524	                    }
525	                }
526	            }
527	
528	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
529	            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
530	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
531	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
532	            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
533	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
534	            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
535	            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);
536	
537	            ch_off += vl;
538	        }
539	        pOut += out_tensor_ch;
540	    }
