                            if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                                in_col2 >= 0 && in_col2 < in_tensor_dim)
                                a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                            if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
                                in_col3 >= 0 && in_col3 < in_tensor_dim)
                                a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                            if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
                                in_col4 >= 0 && in_col4 < in_tensor_dim)
                                a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];

                            /* vqmaccus.vx: acc[e32/M4] += unsigned_scalar * signed_wt[e8/M1] */
                            NDS_VEC_VQMACCUS_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACCUS_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACCUS_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACCUS_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }
            }

